import { createContext } from 'react';

import type { ChartUnit } from '../../core/types/chart-unit.js';
import { MinMax } from '../../core/types/min-max.js';
import {
  WeakMapDimension,
  WeakMapCategory,
  CategoricalBarData,
} from '../types/categorical-bar-chart-data.js';

export interface CategoricalBarFilteredData {
  filteredCategories: CategoricalBarData[];
  filteredDimensions: string[];
  isSingleDimension: boolean;
  minMaxPerUnit: Map<ChartUnit | undefined, MinMax>;
  categoryMap: WeakMapCategory;
  dimensionMap: WeakMapDimension;
  unit?: ChartUnit;
}

export const CategoricalBarFilteredDataContext =
  createContext<CategoricalBarFilteredData>({
    filteredCategories: [],
    filteredDimensions: [],
    isSingleDimension: false,
    minMaxPerUnit: new Map(),
    categoryMap: new WeakMap(),
    dimensionMap: new WeakMap(),
    unit: undefined,
  });
